# Simulate the effect of a duration clause on a noisy rule
def apply_for_clause(firing_intervals, for_seconds):
    # firing_intervals: list of (start, end) seconds where condition was true
    # Returns pages that survive a 'for' duration requirement
    surviving = []
    for start, end in firing_intervals:
        if (end - start) >= for_seconds:
            surviving.append((start + for_seconds, end))
    return surviving

def evaluate(firing_intervals, for_seconds, actionable_windows):
    survivors = apply_for_clause(firing_intervals, for_seconds)
    pages = len(survivors)
    # Did any actionable incident get suppressed entirely?
    missed = 0
    for a_start, a_end in actionable_windows:
        if not any(s <= a_end and e >= a_start for s, e in survivors):
            missed += 1
    return {"pages": pages, "missed_actionable": missed}

# Choose the smallest 'for' that removes noise without missing incidents
