    print(f, evaluate(INTERVALS, f, ACTIONABLE))

# Guard against forgotten permanent silences
from datetime import datetime, timezone, timedelta

MAX_SILENCE = timedelta(days=14)

def audit_silences(silences):
    # silences: list of {id, matchers, created_at, ends_at, comment}
    problems = []
    now = datetime.now(timezone.utc)
    for s in silences:
        if s["ends_at"] is None:
            problems.append((s["id"], "never expires — silences must be time-boxed"))
            continue
        duration = s["ends_at"] - s["created_at"]
        if duration > MAX_SILENCE:
            problems.append((s["id"], f"exceeds max silence of {MAX_SILENCE.days}d"))
        if not s.get("comment"):
            problems.append((s["id"], "missing justification comment"))
    return problems

# Emit a metric so an unexpected rise in active silences pages
def active_silence_count(silences, now):
    return sum(1 for s in silences if s["ends_at"] and s["ends_at"] > now)
